import{_ as a,c as t,o,aP as d}from"./chunks/framework.CcVWUnOI.js";const c=JSON.parse('{"title":"工程化？","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"frontEnd/engineering/index.md","filePath":"frontEnd/engineering/index.md","lastUpdated":1773843913000}'),i={name:"frontEnd/engineering/index.md"};function r(l,e,n,h,s,u){return o(),t("div",null,e[0]||(e[0]=[d('<h1 id="工程化" tabindex="-1">工程化？ <a class="header-anchor" href="#工程化" aria-label="Permalink to &quot;工程化？&quot;">​</a></h1><p>当项目规模变大时，就会出现很多问题，这就是工程化要解决的问题。</p><h2 id="出现的问题" tabindex="-1">出现的问题 <a class="header-anchor" href="#出现的问题" aria-label="Permalink to &quot;出现的问题&quot;">​</a></h2><h3 id="全局污染问题" tabindex="-1">全局污染问题 <a class="header-anchor" href="#全局污染问题" aria-label="Permalink to &quot;全局污染问题&quot;">​</a></h3><ul><li>随着JS文件数量和代码量的增加</li><li>全局变量同名的几率将会陡然上升</li><li>开发人员不得不耗费大量的精力来规避</li></ul><h3 id="依赖混入问题" tabindex="-1">依赖混入问题 <a class="header-anchor" href="#依赖混入问题" aria-label="Permalink to &quot;依赖混入问题&quot;">​</a></h3><p>在js中先引入哪个模块，后引入哪个模块</p><h2 id="模块化" tabindex="-1">模块化 <a class="header-anchor" href="#模块化" aria-label="Permalink to &quot;模块化&quot;">​</a></h2><p>用来解决全局污染和依赖混入问题</p><ul><li>官方标准：ES Module</li><li>社区标准：CommonJS、AMD、CMD、UMD</li></ul><table tabindex="0"><thead><tr><th>特性</th><th>AMD</th><th>CMD</th><th>UMD</th></tr></thead><tbody><tr><td>全称</td><td>Asynchronous Module Definition</td><td>Common Module Definition</td><td>Universal Module Definition</td></tr><tr><td>依赖声明</td><td>依赖前置（开头声明）</td><td>依赖就近（用时 require）</td><td>兼容多种方式</td></tr><tr><td>加载方式</td><td>异步</td><td>异步</td><td>根据环境决定（异步或同步）</td></tr><tr><td>主要用途</td><td>浏览器模块化</td><td>浏览器模块化（已式微）</td><td>通用库，多环境兼容</td></tr><tr><td>代表工具</td><td>RequireJS</td><td>Sea.js</td><td>无特定工具，是一种写法模式</td></tr><tr><td>是否主流</td><td>曾主流，现逐渐被 ES Module 取代</td><td>已不常用</td><td>仍广泛用于第三方库兼容</td></tr></tbody></table><h2 id="包管理" tabindex="-1">包管理 <a class="header-anchor" href="#包管理" aria-label="Permalink to &quot;包管理&quot;">​</a></h2><p>模块化出现后，出现了大量的第三方库，这么多第三方库，如何管理？</p><ul><li>npm</li><li>yarn</li><li>pnpm</li></ul><h2 id="question" tabindex="-1">Question <a class="header-anchor" href="#question" aria-label="Permalink to &quot;Question&quot;">​</a></h2><h3 id="es-module-库适配-commonjs-环境" tabindex="-1">ES Module 库适配 CommonJS 环境 <a class="header-anchor" href="#es-module-库适配-commonjs-环境" aria-label="Permalink to &quot;ES Module 库适配 CommonJS 环境&quot;">​</a></h3><p>开发的 ESM 规范工具库（使用 export/import），下游用户基于 CommonJS 环境（使用 require/module.exports）无法直接引用，请问：</p><h4 id="该问题的核心原因是什么" tabindex="-1">该问题的核心原因是什么？ <a class="header-anchor" href="#该问题的核心原因是什么" aria-label="Permalink to &quot;该问题的核心原因是什么？&quot;">​</a></h4><p>ESM 和 CommonJS 是两种不兼容的模块化规范，ESM 依赖静态分析（export/import），CJS 是动态加载（require/module.exports），Node.js 无法直接用 require 加载纯 ESM 模块，会抛出 ERR_REQUIRE_ESM 错误</p><h4 id="给出至少两种可行的解决方案-并详细说明实现步骤和优缺点。" tabindex="-1">给出至少两种可行的解决方案，并详细说明实现步骤和优缺点。 <a class="header-anchor" href="#给出至少两种可行的解决方案-并详细说明实现步骤和优缺点。" aria-label="Permalink to &quot;给出至少两种可行的解决方案，并详细说明实现步骤和优缺点。&quot;">​</a></h4><ul><li>方案 1：双格式打包。通过 Rollup/tsup 等工具将库同时打包为 ESM 和 CJS 格式，在 package.json 中用 main 声明 CJS 入口、module 声明 ESM 入口</li><li>方案 2：代码适配。在库入口文件中判断环境，同时通过 export 适配 ESM、module.exports 适配 CJS（仅适合简单库）</li></ul><h4 id="推荐最优方案-并解释理由。" tabindex="-1">推荐最优方案，并解释理由。 <a class="header-anchor" href="#推荐最优方案-并解释理由。" aria-label="Permalink to &quot;推荐最优方案，并解释理由。&quot;">​</a></h4><p>双格式打包。理由：符合开源库最佳实践，对用户无感知，同时兼容 ESM/CJS 环境，可处理复杂依赖，扩展性强</p><h3 id="js-库适配低版本-node-js-环境" tabindex="-1">JS 库适配低版本 Node.js 环境 <a class="header-anchor" href="#js-库适配低版本-node-js-环境" aria-label="Permalink to &quot;JS 库适配低版本 Node.js 环境&quot;">​</a></h3><p>封装的 JS 库仅适配 Node.js 24 版本，但公司老项目基于 Node.js 16，无法直接使用该库。请问：</p><h4 id="核心适配难点是什么" tabindex="-1">核心适配难点是什么？ <a class="header-anchor" href="#核心适配难点是什么" aria-label="Permalink to &quot;核心适配难点是什么？&quot;">​</a></h4><p>Node.js 24 与 16 存在 API / 语法差异（如 24 支持的新语法、内置 API，16 可能未实现或行为不同），且依赖的运行时特性、模块兼容逻辑也存在版本鸿沟</p><h4 id="给出两种可行解决方案-简要说明" tabindex="-1">给出两种可行解决方案（简要说明）； <a class="header-anchor" href="#给出两种可行解决方案-简要说明" aria-label="Permalink to &quot;给出两种可行解决方案（简要说明）；&quot;">​</a></h4><ul><li>方案 1：代码降级兼容。使用 Babel 转译新语法，通过 polyfill 补充缺失 API，移除 Node.js 24 专属 API，确保代码在 16 环境可运行</li><li>方案 2：版本分支维护。为老项目单独维护适配 Node.js 16 的库分支，核心逻辑同步更新，打包时指定目标环境为 Node.js 16</li></ul><h4 id="推荐最优方案并说明理由。" tabindex="-1">推荐最优方案并说明理由。 <a class="header-anchor" href="#推荐最优方案并说明理由。" aria-label="Permalink to &quot;推荐最优方案并说明理由。&quot;">​</a></h4><p>代码降级兼容。理由：无需维护多分支，通过工具统一适配，成本更低，且能一次性解决语法 / API 兼容问题，适配效率更高</p><h3 id="esm-与-commonjs-选型决策" tabindex="-1">ESM 与 CommonJS 选型决策 <a class="header-anchor" href="#esm-与-commonjs-选型决策" aria-label="Permalink to &quot;ESM 与 CommonJS 选型决策&quot;">​</a></h3><ul><li>优先选 ESM：项目基于 Node.js 14.13.0+（ESM 支持成熟）、前端工程化项目（Vite/Webpack5+）、需使用顶级 await/ES 模块特性、追求静态分析 / 树摇优化、开源库需多环境兼容</li><li>选 CJS：老项目 / 依赖仅支持 CJS、Node.js 版本＜14.13.0、需动态加载模块（如require(${path}/file.js)）、依赖大量 CJS 专属模块（如__dirname未适配 ESM）</li><li>Node.js 14.13.0 是 ESM 支持从「实验性」转向「稳定版」的关键版本</li></ul>',33)]))}const p=a(i,[["render",r]]);export{c as __pageData,p as default};
